const API_URL = "http://localhost:5000/api"; // Asegúrate que este puerto coincide con tu backend

const getAuthHeaders = () => {
    const savedUser = localStorage.getItem('user-session');
    if (savedUser) {
        try {
            const { token } = JSON.parse(savedUser);
            return {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            };
        } catch (e) {
            return { 'Content-Type': 'application/json' };
        }
    }
    return { 'Content-Type': 'application/json' };
};

export const api = {
    // AUTH
    login: async (email, password) => {
        const response = await fetch(`${API_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ correo: email.trim().toLowerCase(), password })
        });
        if (!response.ok) throw new Error("Error en el login");
        return await response.json(); 
    },

    // PEDIDOS
    crearPedido: async (pedidoData) => {
        const res = await fetch(`${API_URL}/pedidos`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(pedidoData)
        });
        if (!res.ok) throw new Error("Error al crear pedido");
        return await res.json();
    },

    getPedidosCliente: async (clienteId) => {
        try {
            const res = await fetch(`${API_URL}/pedidos/cliente/${clienteId}`, {
                method: 'GET',
                headers: getAuthHeaders()
            });
            if (!res.ok) throw new Error("Error en la respuesta del servidor");
            return await res.json();
        } catch (error) {
            console.error("API Error (getPedidosCliente):", error);
            throw error; // Re-lanzamos para que el componente lo capture
        }
    },

    cancelarPedido: async (pedidoId) => {
        const res = await fetch(`${API_URL}/pedidos/${pedidoId}/estado`, {
            method: 'PATCH',
            headers: getAuthHeaders(),
            body: JSON.stringify({ estado: 'cancelado' })
        });
        if (!res.ok) throw new Error("No se pudo cancelar");
        return await res.json();
    }
};
